s = input()
stack = []
match = {')': '(', ']': '[', '}': '{'}
ok = True
for ch in s:
    if ch in '([{':
        stack.append(ch)
    elif ch in match:
        if not stack or stack[-1] != match[ch]:
            ok = False
            break
        stack.pop()
print('yes' if ok and not stack else 'no')

